INSERT INTO projects (title,slug,stall_area_sqm,stall_area_sqft,stall_height_m,floors,build_year,city,exhibition_id,client_id,description,design_brief,ai_summary,design_style,materials_used,special_features,awards,status,is_featured,display_order) VALUES ('Next View 48 SQM 3 Side Open Stall Exhibition Stall Design at FITAG Tech Expo - IT Show, Gandhinagar 2025','next-view-48-sqm-custom-exhibition-stall-fitag-tech-expo-it-show-gandhinagar-2025',48,516.67,4,1,2025,'Gandhinagar',(SELECT id FROM exhibitions WHERE slug='fitag-tech-expo-it-show' LIMIT 1),(SELECT id FROM clients WHERE slug='next-view' LIMIT 1),'Approach Media designed and fabricated a 48 SQM 3 side open stall exhibition stall for Next View at FITAG Tech Expo - IT Show, Helipad Ground, Gandhinagar. The booth presents a spacious electronics and display technology stall with multiple live TV screens, bold Nextview fascia, demo walls, red carpet zone, and open product experience areas. The stall was planned for strong brand recall, clear product visibility, easy visitor movement, and search-friendly portfolio discovery for security devises, it, hardware, television exhibition projects in Gandhinagar, India.','Create a 48 SQM 3 side open stall custom exhibition stall for Next View that communicates technology, product credibility, and visitor engagement at FITAG Tech Expo - IT Show. The design needed visible branding, product-led storytelling, practical discussion areas, and a premium finish suitable for a busy expo environment.','Next View exhibition stall by Approach Media at FITAG Tech Expo - IT Show, Gandhinagar: 48 SQM 3 side open stall booth with immersive display technology booth with live screen-led product storytelling, designed for product display, lead generation, visitor interaction, and high search relevance around custom exhibition stall design and fabrication in Gujarat.','Immersive display technology booth with live screen-led product storytelling','["Custom wooden build", "laminate finish", "printed graphics", "LED display integration", "acrylic signage", "carpet flooring"]','["Three-side open visibility", "multi-screen display wall", "large brand fascia", "live demo zones", "product counters", "red carpet visitor flow"]',NULL,'published',true,10) ON CONFLICT (slug) DO NOTHING;
