INSERT INTO projects (title,slug,stall_area_sqm,stall_area_sqft,stall_height_m,floors,build_year,city,exhibition_id,client_id,description,design_brief,ai_summary,design_style,materials_used,special_features,awards,status,is_featured,display_order) VALUES ('Voltaic Cable 24 SQM 3 Side Open Stall Exhibition Stall Design at FITAG Tech Expo - IT Show, Gandhinagar 2025','voltaic-cable-24-sqm-custom-exhibition-stall-fitag-tech-expo-it-show-gandhinagar-2025',24,258.33,4,1,2025,'Gandhinagar',(SELECT id FROM exhibitions WHERE slug='fitag-tech-expo-it-show' LIMIT 1),(SELECT id FROM clients WHERE slug='voltaic' LIMIT 1),'Approach Media designed and fabricated a 24 SQM 3 side open stall exhibition stall for Voltaic Cable at FITAG Tech Expo - IT Show, Helipad Ground, Gandhinagar. The booth presents a premium black Voltaic Cable and Katvision stall with illuminated blue edge lighting, product wall displays, dark brand panels, and a high-contrast technology feel. The stall was planned for strong brand recall, clear product visibility, easy visitor movement, and search-friendly portfolio discovery for security devises, it, hardware, television exhibition projects in Gandhinagar, India.','Create a 24 SQM 3 side open stall custom exhibition stall for Voltaic Cable that communicates technology, product credibility, and visitor engagement at FITAG Tech Expo - IT Show. The design needed visible branding, product-led storytelling, practical discussion areas, and a premium finish suitable for a busy expo environment.','Voltaic Cable exhibition stall by Approach Media at FITAG Tech Expo - IT Show, Gandhinagar: 24 SQM 3 side open stall booth with premium dark technology booth with illuminated cable product showcase, designed for product display, lead generation, visitor interaction, and high search relevance around custom exhibition stall design and fabrication in Gujarat.','Premium dark technology booth with illuminated cable product showcase','["Black laminate panels", "acrylic logo signage", "LED strip lighting", "printed graphics", "product display shelving", "carpet flooring"]','["Three-side open layout", "illuminated blue edges", "cable product wall", "premium black fascia", "Katvision co-branding", "demo display zones"]',NULL,'published',true,60) ON CONFLICT (slug) DO NOTHING;
